def get_mercury(year, month, day):
    date_num = year * 10000 + month * 100 + day
    best = EPH[0]
    for e in EPH:
        if e[0] <= date_num:
            best = e
    borderline = any(abs(e[0] - date_num) <= 2 and e[1] != best[1] for e in EPH)
    return SIGNS[best[1]], borderline

def get_sun(month, day):
    bounds = [(3,21,0),(4,20,1),(5,21,2),(6,21,3),(7,23,4),(8,23,5),(9,23,6),(10,23,7),(11,22,8),(12,22,9),(1,20,10),(2,19,11)]
    for i, (sm, sd, si) in enumerate(bounds):
        nm, nd = bounds[(i+1) % len(bounds)][:2]
        if month == sm and day >= sd: return SIGNS[si]
        if month > sm and month < nm: return SIGNS[si]
        if month == nm and day < nd: return SIGNS[si]
    return 'aries'

st.title("社交练习伙伴")
st.caption("输入对方生日，解析水星星座，模拟 Ta 的思维方式和你互动练习")

with st.sidebar:
    st.header("角色设定")
    char_name = st.text_input("角色名字", placeholder="给这个角色起个名字")
    col1, col2, col3 = st.columns(3)
    with col1:
        year = st.number_input("年", min_value=1930, max_value=2019, value=1990)
    with col2:
        month = st.number_input("月", min_value=1, max_value=12, value=6)
    with col3:
        day = st.number_input("日", min_value=1, max_value=31, value=15)
    gender = st.radio("性别", ["女生", "男生", "不设定"])
    start_btn = st.button("开始练习", use_container_width=True)

if 'messages' not in st.session_state:
    st.session_state.messages = []
if 'char_setup' not in st.session_state:
    st.session_state.char_setup = None

if start_btn:
    if not char_name:
        char_name = "Ta"
    mercury_sign, borderline = get_mercury(int(year), int(month), int(day))
    sun_sign = get_sun(int(month), int(day))
    mer = MERCURY_DATA[mercury_sign]
    sun = MERCURY_DATA[sun_sign]
    st.session_state.char_setup = {
        'name': char_name,
        'mercury': mercury_sign,
        'mercury_name': mer['name'],
        'style': mer['style'],
        'tip': mer['tip'],
        'traits': mer['traits'],
        'sun_name': sun['name'],
        'gender': gender,
        'borderline': borderline,
    }
    st.session_state.messages = []

if st.session_state.char_setup:
    setup = st.session_state.char_setup

    with st.expander("星盘解析", expanded=False):
        col1, col2 = st.columns(2)
        with col1:
            st.metric("太阳星座", setup['sun_name'])
        with col2:
            st.metric("水星星座", setup['mercury_name'])
        st.info("思维与表达方式：" + setup['style'])
        st.success("提示：" + setup['tip'])
        if setup['borderline']:
            st.warning("该日期接近水星换座，存在误差可能")

    for msg in st.session_state.messages:
        with st.chat_message(msg['role']):
            st.write(msg['content'])

    user_input = st.chat_input("和 " + setup['name'] + " 说点什么…")
    if user_input:
        st.session_state.messages.append({'role': 'user', 'content': user_input})
        with st.chat_message('user'):
            st.write(user_input)

        gender_tip = {'女生':'性别女，语气自然女性化。','男生':'性别男，语气自然男性化。','不设定':'语气自然。'}[setup['gender']]
        system_prompt = (
            "你正在扮演角色「" + setup['name'] + "」。\n"
            "水星星座：" + setup['mercury_name'] + "\n"
            "表达方式：" + setup['style'] + "\n"
            + gender_tip + "\n"
            "规则：严格用水星" + setup['mercury_name'] + "的风格说话；只输出角色说的话，1-3句；不加任何前缀说明；不暴露AI身份；用中文。"
        )

        api_key = st.secrets.get("GEMINI_API_KEY", "")
        if not api_key:
            st.error("请先在 Secrets 里设置 GEMINI_API_KEY")
        else:
            genai.configure(api_key=api_key)
            model = genai.GenerativeModel(
                model_name="gemini-2.0-flash",
                system_instruction=system_prompt
            )
            history_for_gemini = []
            for msg in st.session_state.messages[:-1]:
                role = "user" if msg['role'] == 'user' else "model"
                history_for_gemini.append({"role": role, "parts": [msg['content']]})
            chat = model.start_chat(history=history_for_gemini)
            with st.spinner(""):
                response = chat.send_message(user_input)
                reply = response.text
            st.session_state.messages.append({'role': 'assistant', 'content': reply})
            with st.chat_message('assistant'):
                st.write(reply)
else:
    st.info("在左边填写角色信息，点「开始练习」就可以开始了")
